/// <reference types="vite-plugin-electron/electron-env" />

declare namespace NodeJS {
  interface ProcessEnv {
    /**
     * The built directory structure
     *
     * ```tree
     * ├─┬─┬ dist
     * │ │ └── index.html
     * │ │
     * │ ├─┬ dist-electron
     * │ │ ├── main.js
     * │ │ └── preload.js
     * │
     * ```
     */
    APP_ROOT: string
    /** /dist/ or /public/ */
    VITE_PUBLIC: string
  }
}

// Exposed by preload.ts. Optional: absent when the renderer runs in a plain
// browser (e.g. `vite` opened directly) rather than inside Electron.
interface Window {
  fileVaultApi?: import('../shared/types').FileVaultApi
}
